import{_ as e,o,c,ag as a}from"./chunks/framework-C5-Jzrz4.js";const i=JSON.parse('{"title":"架构设计说明","description":"项目分层、包职责和文档站点组织","frontmatter":{"title":"架构设计说明","description":"项目分层、包职责和文档站点组织"},"headers":[],"relativePath":"scripts/guide/03-架构设计说明.md","filePath":"scripts/guide/03-架构设计说明.md","lastUpdated":null}');const l=e({name:"scripts/guide/03-架构设计说明.md"},[["render",function(e,i,l,d,s,t){return o(),c("div",null,[...i[0]||(i[0]=[a('<h1 id="架构设计说明" tabindex="-1">架构设计说明 <a class="header-anchor" href="#架构设计说明" aria-label="Permalink to &quot;架构设计说明&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>本项目采用 Monorepo。应用层、组合能力层、核心能力层、工具层分工明确，<code>apps/web-antd</code> 负责最终组装。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>功能设计前的模块落点判断</li><li>共享能力抽取与依赖边界确认</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/src</code></li><li><code>packages/@core/*</code></li><li><code>packages/effects/*</code></li><li><code>packages/{constants,icons,locales,preferences,stores,styles,types,utils}</code></li><li><code>internal/*</code></li><li><code>docs/.vitepress/config.mts</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="分层结构" tabindex="-1">分层结构 <a class="header-anchor" href="#分层结构" aria-label="Permalink to &quot;分层结构&quot;">​</a></h3><ul><li>应用层：<code>apps/web-antd/src</code></li><li>组合能力层：<code>packages/effects/*</code></li><li>核心能力层：<code>packages/@core/*</code></li><li>基础工具层：<code>packages/constants</code>、<code>packages/types</code>、<code>packages/utils</code> 等</li><li>工程工具层：<code>internal/*</code></li></ul><h3 id="主应用结构-apps-web-antd-src" tabindex="-1">主应用结构（<code>apps/web-antd/src</code>） <a class="header-anchor" href="#主应用结构-apps-web-antd-src" aria-label="Permalink to &quot;主应用结构（`apps/web-antd/src`）&quot;">​</a></h3><ul><li><code>adapter</code>：表单与组件适配</li><li><code>api</code>：接口组织</li><li><code>components</code>：应用层业务组件</li><li><code>layouts</code>：布局接入层</li><li><code>locales</code>：应用语言包装</li><li><code>router</code>：路由与守卫</li><li><code>store</code>：应用层 Pinia Store</li><li><code>utils</code>：HTTP、消息、上下文等工具</li><li><code>views</code>：页面视图</li></ul><h3 id="packages-职责归类-当前源码" tabindex="-1">packages 职责归类（当前源码） <a class="header-anchor" href="#packages-职责归类-当前源码" aria-label="Permalink to &quot;packages 职责归类（当前源码）&quot;">​</a></h3><ul><li>UI 组件/组件能力： <ul><li><code>@vben/common-ui</code></li><li><code>@vben-core/form-ui</code></li><li><code>@vben-core/layout-ui</code></li><li><code>@vben-core/menu-ui</code></li><li><code>@vben-core/popup-ui</code></li><li><code>@vben-core/shadcn-ui</code></li><li><code>@vben-core/tabs-ui</code></li></ul></li><li>布局能力：<code>@vben/layouts</code></li><li>表单能力：<code>@vben-core/form-ui</code></li><li>菜单/标签页/弹窗：<code>@vben-core/menu-ui</code>、<code>@vben-core/tabs-ui</code>、<code>@vben-core/popup-ui</code></li><li>插件能力：<code>@vben/plugins</code></li><li>请求能力：<code>@vben/request</code></li><li>权限能力：<code>@vben/access</code></li><li>工具与基础：<code>@vben/utils</code>、<code>@vben/constants</code>、<code>@vben/locales</code>、<code>@vben/preferences</code>、<code>@vben/stores</code>、<code>@vben/types</code>、<code>@vben/styles</code>、<code>@vben/icons</code></li></ul><h3 id="文档站点组织" tabindex="-1">文档站点组织 <a class="header-anchor" href="#文档站点组织" aria-label="Permalink to &quot;文档站点组织&quot;">​</a></h3><ul><li>站点根：<code>docs</code></li><li>文档主目录：<code>docs/scripts</code></li><li>站点配置：<code>docs/.vitepress/config.mts</code></li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>新增通用能力时，优先判断应放入 <code>packages</code> 还是仅应用层。</li><li><code>components</code> 文档只记录组件与组件能力，不把纯工具包写进组件体系。</li><li>变更目录结构后必须同步 <code>docs/.vitepress/config.mts</code> 与 <code>reference</code> 索引。</li></ul>',18)])])}]]);export{i as __pageData,l as default};
